class Solution {
public:
    int minSwapsCouples(vector<int>& row) {
        int n = row.size() / 2;
        int swaps = 0;
        for (int i = 0; i < n; ++i) {
            if (row[i] % 2 != i) {
                int j = row[i] / 2;
                int k = row[j * 2 + 1];
                row[i] = k;
                row[j * 2 + 1] = row[i];
                swaps++;
            }
        }
        return swaps;
    }
};
